import java.util.*;
public class java_52967_SessionManager_A01 {   //session object name can be any meaningful names in your application such as 'UserSession', etc., it will not matter much, only for understanding purpose of session management concept and this is just a simple example 
    private String id;         //unique identifier to identify the user's current Session. It could have some kind hash like UUID or token based approach used in real world scenario where same sessions are needed across users (like login with different usernames/passwords)  
     Map<String, Object> data = new HashMap<>();  //store session related information here which can be user specific details ,product added to carts etc. It is just a placeholder for real world scenario and this will have only small scope in our current example where we are storing simple values as it makes the problem easy
      static List<CustomSession> sessions = new ArrayList<>();  //static list of all active users who can login at any point, to track currently logged-in user(s)  
       public java_52967_SessionManager_A01(String id) {    this.id=id; }     //constructor for creating a session with specific unique identifier and assigning it an ID if not given by the developer then we should generate UUID or token  based on requirement at that time, in case of new login user only use 'this' method
       public Object get(String key){   return data.getOrDefault (key , null); }    //retrieve specific value from session using a Key     if not found the default will be returned which is usually Null or Default Value for That type  in case of Integer and so on, This would handle simple use cases
       public void put(String key, Object val){ data.put (key ,val ); }    //set specific value to session using a Key     if not given then we should add that as default behaviour which is usually Null or Default Value for That type  in case of Integer and so on     `Integer example
       public void invalidate(){ sessions.remove(this);   /*In this simple implementation, when the user's Session gets removed from 'active users list'. In real world application , it would be different like removing a User record or just unsetting an expired session */ }  //unset specific value to clear space in memory for next requests
}